/**
 * NovelStatus
 * 小说阅读状态
 */
export type NovelStatus = 'unread' | 'reading' | 'completed' | 'paused';

/**
 * Novel
 * 小说实体，包含小说基本信息和阅读状态
 */
export interface Novel {
  /** 唯一标识 */
  id: string;
  /** 小说标题 */
  title: string;
  /** 作者 */
  author: string;
  /** 封面图片URL */
  coverImage: string;
  /** 小说描述 */
  description: string;
  /** 文件路径 */
  filePath: string;
  /** 总页数 */
  totalPages: number;
  /** 当前阅读页数 */
  currentPage: number;
  /** 最后阅读时间 (ISO Date String) */
  lastReadAt: string;
  /** 创建时间 (ISO Date String) */
  createdAt: string;
  /** 更新时间 (ISO Date String) */
  updatedAt: string;
  /** 阅读状态 */
  status: NovelStatus;
  /** 阅读进度百分比 */
  progressPercentage: number;
}

/**
 * Category
 * 小说分类标签
 */
export interface Category {
  /** id */
  id: string;
  /** name */
  name: string;
  /** color */
  color: string;
  /** description */
  description: string;
}

import { Novel } from "./Novel";

/**
 * ReadingNote
 * 阅读笔记
 */
export interface ReadingNote {
  /** 唯一标识 */
  id: string;
  /** 关联的小说ID */
  novelId: string;
  /** 页码 */
  pageNumber: number;
  /** 笔记内容 */
  content: string;
  /** 创建时间 (ISO Date String) */
  createdAt: string;
  /** 更新时间 (ISO Date String) */
  updatedAt: string;
}

import { Novel } from "./Novel";

/**
 * ReadingSession
 * 阅读会话记录
 */
export interface ReadingSession {
  /** 唯一标识 */
  id: string;
  /** 关联的小说ID */
  novelId: string;
  /** 开始页码 */
  startPage: number;
  /** 结束页码 */
  endPage: number;
  /** 阅读时长（单位：秒） */
  duration: number;
  /** 创建时间 (ISO Date String) */
  createdAt: string;
}

import { Novel } from "./Novel";

/**
 * Bookmark
 * 书签
 */
export interface Bookmark {
  /** 唯一标识 */
  id: string;
  /** 关联的小说ID */
  novelId: string;
  /** 页码 */
  pageNumber: number;
  /** 描述 */
  description: string;
  /** 创建时间 (ISO Date String) */
  createdAt: string;
}
